async function bindleftCommonSearchdropdown(instance, fieldName) {
    var vm = instance;    
    if (fieldName == 'WORKCODE') {
        DataService.GetWorkCodes().then((response) => {
            if (response.data.result.length > 0) {
                vm.leftSearchFields[2].listOptions = [];
                response.data.result.forEach(element => {
                    let Obj = {
                        value: `${element.Value}`,
                        name: element.Text
                    }
                    vm.leftSearchFields[2].listOptions.push(Obj);
                });
            }
        });
    }
    if (fieldName == 'STATE') {
        var params = `countryId=223&includeCandaState=true`;
        DataService.GetStateListByCountryId(params).then((response) => {
            if (response.data.result.length > 0) {
                vm.leftSearchFields[3].listOptions = [];
                const StateNames = response.data.result;
                StateNames.forEach(element => {
                    let Obj = {
                        value: `${element.ISO_CODE_3}`,
                        name: `${element.STATE_NAME} (${element.ISO_CODE_3})`
                    }
                    vm.leftSearchFields[3].listOptions.push(Obj);
                });
            }

        });
    }
    if (fieldName === "BILLER") {       
           try {
               const url = `reqFrom=all&moduleName=Billing`;
               const BillerResponse = (await DataService.GetBillerList(url));
               const BillerResponses=JSON.parse(BillerResponse.data.result)
               if (BillerResponses) {                
                   const BillerOptions = BillerResponses.map(item => ({
                       description: item.EMAIL_ID || null,
                       displayValue: item.USERNAME,
                       groupText: item.DEPARTMENT_NAME || null,
                       groupValue: null,
                       metaData: item,
                       text: item.USERNAME,     
                       value: item.USERID       
                   }));
                   const billerField = vm.leftSearchFields.find(f => f.fieldName === 'Biller');
                   if (billerField) {billerField.listOptions = BillerOptions;}
               }
           } catch (error) {
               console.error('Error loading Biller:', error);
           }
        
    }
}


export default { buttons, leftsearchSchema, listActions, bindleftCommonSearchdropdown }; 