<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>
    <div class="modal d-block">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header theme-primary partition-full  d-flex">
                    <h4 class="modal-title">{{ EditData && EditData.RATE_SCHEDULE_ID ? $t('UpdateRate') : $t('addrate') }}</h4>
                    <span class="user-guide">
                            <a class="ancuserguide text-white" data-toggle="collapse" href="#collapseReplyUG"
                                role="button" aria-expanded="false" aria-controls="collapseExample"> <em
                                    class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}</a>
                            <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                                <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                    <div class="con" v-html="$t('RateScheduleAdd')"></div>
                                </div>
                            </div>
                        </span>
                    <button type="button" class="close" v-on:click="Close">
                        <em class="fa fa-times" aria-hidden="true"></em>
                    </button>
                </div>
                <div class="modal-body">
                    <dynamic-form lang="en" ref="ResourceRate" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="onSubmit" :mandatorytext='MandatoryString'></dynamic-form>
                </div>
            </div>
        </div>
    </div>
</div>
</template>

<script>
import DataService from '../../services/DataService';
import {locateBillingService } from "../../services/locateBillingService";
export default {
     props: {
        EditData: {
            type: Array,
            required: false,
        },
    },
    data() {
        return {
            isLoading: false,
            MandatoryString:'Fields marked with an asterisk (*) are mandatory.',
            companyId: null,
            userId: null,
            PageSize: 100,
            PageNumber: 1,
            searchCondition: '',
            GroupNewData: [],
            UtiltityNames: [],
            StateNames: [],
            WorkCodes: [],
            StatusData: [],
            clientList:[],
            FormSchema: [{
                    layoutType: "triple",
                    Data: [
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('ContractCompanyName'),
                            name: "ContractName",
                            value: "",
                            placeholder: this.$t('SearchAndSelectContract'),
                            visibility: true,
                            isSearch: false,
                            disabled: this.EditData.RATE_SCHEDULE_ID > 0 ? true: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    active: true,
                                    inactive: true,
                                    clear: true
                                },
                                isMultiple: false,
                                groupFields: ['groupText'],
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                onChange: this.onSelectionChange,                               
                            },
                        },
                     {
                            astype: "SearchableSelectField",
                            label: this.$t('UtilityName'),
                            name: "UtilityName",
                            value: "",
                            placeholder: "Select Utility Name",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                selectAll: true,
                                active: false,
                                inactive: false,
                                clear: true},
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": true
                            },
                            disabled: this.EditData.RATE_SCHEDULE_ID > 0 ? true: false
                        },
                    {
                        astype: "SelectField",
                        label: this.$t('State'),
                        name: "State",
                        value: "",
                        placeholder: this.$t('Select State'),
                        validationRules: {
                            "required": true
                        },
                        config: {
                            options: [],
                        },
                        visibility: true
                    },
                    {
                        astype: "SelectField",
                        label: this.$t('WorkCode'),
                        name: "WorkCode",
                        value: "",
                        placeholder: this.$t('Select Work Code'),
                        validationRules: {
                            "required": true
                        },
                        config: {
                            options: [],
                        },
                        visibility: true
                    },
                    {
                        astype: "DateField",
                        label: this.$t('Start Date (M/D/YYYY)'),
                        name: "StartDate",
                        value: new Date(),
                        visibility: true,
                        placeholder: this.$t('StartDate'),
                        config: {
                            format: "MM/DD/YYYY"
                        },
                        validationRules: {
                            "required": true
                        }
                    },
                    {
                        astype: "DateField",
                        label: this.$t('End Date (M/D/YYYY)'),
                        name: "EndDate",
                        value: new Date(new Date().setFullYear(new Date().getFullYear() + 1)),
                        visibility: true,
                        placeholder: this.$t('EndDate'),
                        config: {
                            format: "MM/DD/YYYY"
                        },
                        validationRules: {
                            "required": true
                        },
                    },
                    {
                        astype: "NumericField",
                        label: this.$t('Rate'),
                        name: "Rate",
                        value: "",
                        placeholder: this.$t('Enter Rate'),
                        validationRules: {
                            "required": true
                        },
                        config: {
                            options: [],
                        },
                        visibility: true
                    },
                    {
                        astype: "SelectField",
                        label: this.$t('Status'),
                        name: "Status",
                        value: "",
                        placeholder: this.$t('Select Status'),
                        validationRules: {
                            //"required": false
                        },
                        config: {
                            options: [],
                        },
                        visibility: true
                    },
                    {
                        astype: "TextField",
                        label: this.$t('CustomerWorkCode'),
                        name: "CustomerWorkCode",
                        value: "",
                        placeholder: this.$t('Enter Customer Work Code'),
                        validationRules: {
                           // "required": false
                        },
                        config: {
                            options: [],
                        },
                        visibility: true
                    }]
                },
                {
                    layoutType: "single",
                    Data: [{
                        astype: "TextAreaField",
                        label: this.$t('Comment'),
                        name: "Comment",
                        value: "",
                        placeholder: this.$t('Enter Comment'),
                        validationRules: {
                            //"required": false
                        }
                    }]
                },
                {
                    layoutType: "triple",
                    Data: [
                       {
                        astype: "SelectField",
                        label: this.$t('CostCenters'),
                        name: "CostCenter",
                        value: "",
                        placeholder: this.$t('Select Cost Centers'),
                        validationRules: {"required": false },
                        config: {options: []},
                        visibility: false
                    },
                ]
                }
            ],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible: true,
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Close,
                }
            ]
        }
    },
    created: async function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        await vm.GetDDLCompanyContractClients();     
        await vm.GetStateListByCountryId();
        await vm.GetCostCenters();
        await vm.GetWorkCodes();
        await vm.GetStatusList();
        if(vm.EditData.RATE_SCHEDULE_ID>0){        
            (vm.FormSchema)[0].Data[0].value=vm.EditData.CLIENT_ID;
            (vm.FormSchema)[0].Data[6].value=vm.EditData.AMOUNT;
            (vm.FormSchema)[0].Data[8].value=vm.EditData.Billing_Code;
            await vm.onSelectionChange('client','',vm.EditData.CLIENT_ID);
            vm.isLoading = true; 
            setTimeout(() => {                              
                setTimeout(() => {
                  (vm.FormSchema)[0].Data[1].value=vm.EditData.UTILITY_ID; 
                   vm.isLoading = false; 
                }, 400);              
                (vm.FormSchema)[0].Data[2].value=vm.EditData.STATE_CODE;
                (vm.FormSchema)[0].Data[3].value=vm.EditData.WORKCODE_ID?.toString();
                (vm.FormSchema)[0].Data[7].value=vm.EditData.STATUS_ID;
                (vm.FormSchema)[2].Data[0].value=vm.EditData.COST_CENTER?.toString();
            }, 200);          
            
            (vm.FormSchema)[1].Data[0].value=vm.EditData.COMMENT;
            (vm.FormSchema)[0].Data[4].value=vm.$options.filters.formatDate(vm.EditData.START_DATE)
            (vm.FormSchema)[0].Data[5].value=vm.$options.filters.formatDate(vm.EditData.END_DATE)
        }
    },
    methods: {

        GetDDLCompanyContractClients: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM`;
            await locateBillingService.getClientList(url).then(response => {
                vm.isLoading = false;
                vm.clientList = response.data.items;
                vm.$refs.ResourceRate.updateProperty("ContractName", "config.options", vm.clientList);
                vm.$refs.ResourceRate.UpdateKeyValue();
            }).catch(error => {
                vm.isLoading = false;
                vm.clientList = []; 
                vm.$refs.ResourceRate.updateProperty("ContractName", "config.options", vm.clientList);
                vm.$refs.ResourceRate.UpdateKeyValue();
                console.error('Error fetching client list:', error);
            }).finally(() => {
                vm.isLoading = false;
            });
        },
          onSelectionChange: async function(value, x) {
            var vm = this;
            vm.isLoading = true;
            if(x==null){
                (vm.FormSchema)[0].Data[1].value='';
                vm.$refs.ResourceRate.validateForm.reset();
            }
            vm.selectedClientId = x;
            var url = `clientId=${x}&configId=&reqFrom=&clientIds=`;
            await locateBillingService.getUtilityList(url).then(response => {
                vm.isLoading = false;
                let SelectedUtilityList = [];
                var UtilityList = response.data;
                if (UtilityList != null) {
                    UtilityList.forEach(item => {
                        let obj = {
                            description: null,
                            displayValue: item.UTILITY_NAME,
                            groupText: null,
                            groupValue: null,
                            metaData: null,
                            text: item.UTILITY_NAME,
                            value: item.UTILITY_ID
                        };
                        SelectedUtilityList.push(obj);
                    });
                     vm.$refs.ResourceRate.updateProperty("UtilityName", "config.options", SelectedUtilityList);
                     vm.$refs.ResourceRate.UpdateKeyValue();
                }
            }).catch(error => {
                vm.isLoading = false;
            }).finally(() => {
                vm.isLoading = false;
            });
        },       

        GetStateListByCountryId: function () {                     
            var vm = this;            
            var url = `countryId=${223}&includeCandaState=true`                       
            DataService.GetStateListByCountryId(url).then((response) => {                          
                if (response.data.result.length > 0) {                    
                    (vm.FormSchema)[0].Data[1].config.options = [];
                    vm.StateNames =response.data.result;
                    vm.StateNames.forEach((itm, index) => {
                        (vm.FormSchema)[0].Data[2].config.options.push({
                            name: `${itm.STATE_NAME}  (${itm.ISO_CODE_3})`,
                            value: `${itm.ISO_CODE_3 }`
                        })
                    })
                    vm.$refs.ResourceRate.UpdateKeyValue();
                    vm.isLoading = false;
                }
                vm.isLoading = false
            });
        },

        GetWorkCodes: function () {                 
            var vm = this;                      
            DataService.GetWorkCodes().then((response) => {               
                if (response.data.result.length > 0) {
                    (vm.FormSchema)[0].Data[3].config.options = [];
                    vm.WorkCodes = (response.data.result);
                    vm.WorkCodes.forEach((itm, index) => {
                        (vm.FormSchema)[0].Data[3].config.options.push({
                            name: `${itm.Text}`,
                            value: `${itm.Value}`
                        })
                    })
                    vm.$refs.ResourceRate.UpdateKeyValue();
                    vm.isLoading = false;
                }
                vm.isLoading = false
            });
        },

        GetStatusList() {
            const vm = this;
            vm.isLoading = true;
            try {
                DataService.GetClientStatusList().then((response) => {
                    const data = JSON.parse(response.data);
                    if (data && Array.isArray(data)) {
                        const filteredStatus = data.filter(
                            itm => itm.STATUS_ID === 1001 || itm.STATUS_ID === 1002
                        );
                        vm.FormSchema[0].Data[7].config.options = [];
                        filteredStatus.forEach(itm => {
                            vm.FormSchema[0].Data[7].config.options.push({
                                name: itm.STATUS,
                                value: itm.STATUS_ID
                            });
                        });
                        vm.$refs.ResourceRate.UpdateKeyValue();
                    }
                    vm.isLoading = false;
                });
            } catch (error) {
                vm.isLoading = false;
            }
        },

        GetCostCenters: function () {                    
            var vm = this;                                
            DataService.GetCostCenters().then((response) => {                          
                if (response.data.length > 0) {  
                    debugger;                
                    (vm.FormSchema)[2].Data[0].config.options = [];
                    const Center =response.data;
                    Center.forEach((itm, index) => {
                        (vm.FormSchema)[2].Data[0].config.options.push({
                            name: `${itm.TEXT}`,
                            value: `${itm.VALUE }`
                        })
                    })
                    vm.$refs.ResourceRate.UpdateKeyValue();
                    vm.isLoading = false;
                }
                vm.isLoading = false
            });
        },


        onSubmit(formfields, val) {
            var vm = this;
             var vm = this;
            const result =  vm.$refs.ResourceRate.validateForm.validate();
            if (result) {
                const objData = {
                    RateScheduleId: vm.EditData && vm.EditData.RATE_SCHEDULE_ID > 0 ? Number(vm.EditData.RATE_SCHEDULE_ID): 0,
                    ClientId: Number(formfields.ContractName),
                    // API expects comma-separated string
                    UtilityId: Array.isArray(formfields.UtilityName) ? formfields.UtilityName.join(",") : String(formfields.UtilityName),
                    WorkCodeId: Number(formfields.WorkCode),
                    Rate: Number(formfields.Rate),
                    StartDate: formfields.StartDate ? new Date(formfields.StartDate).toISOString() : null,
                    EndDate: formfields.EndDate ? new Date(formfields.EndDate).toISOString() : null,
                    State: String(formfields.State),
                    Comment: formfields.Comment || "",
                    Notes: formfields.Comment || "",
                    CostCenter: Number(formfields.CostCenter),
                    StatusId: Number(formfields.Status?formfields.Status:1001),
                    BCode: formfields.CustomerWorkCode ? String(formfields.CustomerWorkCode): ""
                };
                var obj = JSON.stringify(objData);
                var params = `objData=${encodeURIComponent(obj)}`;
                 DataService.AddUpdateRate(obj).then(response => {                    
                    if (response.data != null) {
                        const Result=JSON.parse(response.data)[0];
                        if (parseInt(Result.RESULT) === 1) {                            
                            vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('RateSchedule')]), "success", true, vm.$t("Alert"));
                            vm.Close();
                        } else if (Result.Success == 2) {
                             vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('RateSchedule')]), "Success", true, vm.$t('Alert'));
                             vm.Close();
                        }
                        else if(Result.Result.length > 5){                           
                             vm.ShowAlert(vm.$t('OverlapRecordsUpdateRates', [Result.Result]), "warning", true, vm.$t('Alert'));
                            // vm.ShowAlert(vm.$t("OverlapDateRangeForUpdateRates", { 0: Result.Result }), "warning", true, vm.$t("Alert"));                                                 
                        }
                        else if (Result.Success == 0 && Result.Error== 'EXISTS') {
                            vm.ShowAlert(vm.$t('AlreadyExists', [vm.$t('RateSchedule')]), "warning", true, vm.$t("Alert"));                            
                        } else {
                            vm.ShowAlert(vm.$t("UnknownError"), "failure", vm.$t('Alert'));
                        }
                    }
                });

            }
        },
        Close: function () {
            this.$parent.FetchData();
            this.$parent.isShowAddRate = false;
        }
    }
}
</script>